story-context.interfaces:
- Permission entity schema:
  model Permission {
    id: UUID (primary key)
    module: String
    action: String
    description: String? (optional)
    createdAt: DateTime
    @@unique([module, action])
    @@index([module])
  }

- PERMISSIONS constant structure:
  export const PERMISSIONS = {
    USERS: {
      CREATE: 'USERS.CREATE',
      VIEW: 'USERS.VIEW',
      UPDATE: 'USERS.UPDATE',
      DELETE: 'USERS.DELETE',
    },
    PERMISSIONS: {
      VIEW: 'PERMISSIONS.VIEW',
      ASSIGN: 'PERMISSIONS.ASSIGN',
      REVOKE: 'PERMISSIONS.REVOKE',
    },
    FILES: {
      CREATE: 'FILES.CREATE',
      VIEW: 'FILES.VIEW',
      DELETE: 'FILES.DELETE',
      VIEW_ALL: 'FILES.VIEW_ALL',
    },
  } as const;

- ActionEnum:
  export enum ActionEnum {
    CREATE = 'CREATE',
    VIEW = 'VIEW',
    UPDATE = 'UPDATE',
    DELETE = 'DELETE',
  }

- @Permission decorator usage:
  @Permission('USERS', ActionEnum.CREATE)
  async create() { ... }
